import{_ as n,o as t,c as s,ai as e}from"./chunks/framework.CgfAAQZ5.js";const u=JSON.parse('{"title":"Padding 与 Truncation","description":"","frontmatter":{},"headers":[],"relativePath":"ai-learning-notes/padding-truncation.md","filePath":"ai-learning-notes/padding-truncation.md","lastUpdated":1779177473000}'),i={name:"ai-learning-notes/padding-truncation.md"};function p(o,a,r,d,l,c){return t(),s("div",null,[...a[0]||(a[0]=[e(`<h1 id="padding-与-truncation" tabindex="-1">Padding 与 Truncation <a class="header-anchor" href="#padding-与-truncation" aria-label="Permalink to &quot;Padding 与 Truncation&quot;">​</a></h1><p>NLP 里不同句子长度不一样，但矩阵每行必须一样长。解决办法：</p><h2 id="切-truncation" tabindex="-1">切（Truncation） <a class="header-anchor" href="#切-truncation" aria-label="Permalink to &quot;切（Truncation）&quot;">​</a></h2><p>太长的砍掉尾部。</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>设定最大长度 = 4</span></span>
<span class="line"><span></span></span>
<span class="line"><span>「今天 天气 真 好 啊」 → 「今天 天气 真 好」</span></span>
<span class="line"><span>                            「啊」被丢弃</span></span></code></pre></div><h2 id="补-0-padding" tabindex="-1">补 0（Padding） <a class="header-anchor" href="#补-0-padding" aria-label="Permalink to &quot;补 0（Padding）&quot;">​</a></h2><p>太短的在后面填 [PAD] token。</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>设定最大长度 = 5</span></span>
<span class="line"><span></span></span>
<span class="line"><span>「我 爱 中国」 → 「我 爱 中国 [PAD] [PAD]」</span></span></code></pre></div><p>[PAD] token 在 attention 计算里会被 mask 掉（注意力分数设为 -∞，softmax 后权重 = 0），不影响实际内容的计算。</p><h2 id="和归一化的关系" tabindex="-1">和归一化的关系 <a class="header-anchor" href="#和归一化的关系" aria-label="Permalink to &quot;和归一化的关系&quot;">​</a></h2><p>补 0 之后如果直接用 <strong>BatchNorm</strong>，大量的 0 值会拉低这批数据的均值和方差，导致统计量不准。</p><p><strong>LayerNorm</strong> 不受影响——每个样本独立算，自己的 [PAD] 只影响自己的均值方差，不干扰别人。</p><p>这也是 Transformer 选择 LayerNorm 的原因之一：NLP 数据天然不等长，Padding 大量存在。</p>`,13)])])}const g=n(i,[["render",p]]);export{u as __pageData,g as default};
